using System;
using System.IO;
using System.Text;

namespace LCPSAutomate
{
    public class LogWriterTest
    {
        private readonly string _targetDirectory;

        public LogWriterTest(string targetDirectory)
        {
            _targetDirectory = targetDirectory ?? throw new ArgumentNullException(nameof(targetDirectory));
            // 确保目录存在
            if (!Directory.Exists(_targetDirectory))
            {
                Directory.CreateDirectory(_targetDirectory);
            }
        }

        public void WriteTestLog()
        {
            string logFileName = $"test_{DateTime.Now:yyyyMMddHHmmss}.txt";
            string logFilePath = Path.Combine(_targetDirectory, logFileName);

            for(var i = 0; i < 100; i++)
            {
                using (StreamWriter writer = new StreamWriter(logFilePath, false, Encoding.UTF8))
                {
                    string timestamp = "2025-10-10 19:15:39.8236";
                    string timestamp2 = "2025-10-10 19:15:16.1578";

                    // 写入第三条记录
                    writer.WriteLine($"{timestamp} [INFO ] ID情報 3枚目");
                    writer.WriteLine($"{timestamp} [INFO ] > 品番: GN2519002070");
                    writer.WriteLine($"{timestamp} [INFO ] > 包装区分: 0Q");
                    writer.WriteLine($"{timestamp} [INFO ] > 収容数: 60");
                    writer.WriteLine($"{timestamp} [INFO ] > 仕切り数: 60");
                    writer.WriteLine($"{timestamp} [INFO ] > 市販品フラグ: 0");
                    writer.WriteLine($"{timestamp} [INFO ] > マガジン番号: 65");
                    writer.WriteLine($"{timestamp} [INFO ] 収容ワークシリアル情報 OK");
                    writer.WriteLine($"{timestamp} [INFO ] かんばん照合 OK");
                    writer.WriteLine($"{timestamp} [INFO ] トレース情報書込み OK");
                    writer.WriteLine($"{timestamp} [INFO ] CHANGE STATE: NextIDRead --> FirstIDRead");

                    // 写入第二条记录
                    writer.WriteLine($"{timestamp2} [INFO ] ID情報 2枚目");
                    writer.WriteLine($"{timestamp2} [INFO ] > 品番: GN2519002070");
                    writer.WriteLine($"{timestamp2} [INFO ] > 包装区分: 0Q");
                    writer.WriteLine($"{timestamp2} [INFO ] > 収容数: 60");
                    writer.WriteLine($"{timestamp2} [INFO ] > 仕切り数: 60");
                    writer.WriteLine($"{timestamp2} [INFO ] > 市販品フラグ: 0");
                    writer.WriteLine($"{timestamp2} [INFO ] > マガジン番号: 62");
                    writer.WriteLine($"{timestamp2} [INFO ] 収容ワークシリアル情報 OK");
                    writer.WriteLine($"{timestamp2} [INFO ] かんばん照合 OK");
                    writer.WriteLine($"{timestamp2} [INFO ] CHANGE STATE: NextIDRead --> NextIDRead");
                    writer.WriteLine($"{timestamp2} [INFO ] <QR読込>: DISC5060020000010091000210125104151120712305152071530815408155092177970-30E-S110-M2        GN251900-24100P0000060Q102 00038482025101025101001010040001[CR]");

                    // 写入RFID读取记录
                    writer.WriteLine($"{timestamp} [INFO ] <RFID読込1>: address: 0x000 size: 0x7CF");
                    writer.WriteLine($"{timestamp} [INFO ] <RFID読込1>: ");
                }
            }
            
        }
    } 
}